ALTER TABLE agent_profile_version
    ADD COLUMN IF NOT EXISTS routing_model VARCHAR(64);

UPDATE agent_profile_version
SET routing_model = COALESCE(NULLIF(TRIM(chat_model), ''), 'qwen-plus')
WHERE routing_model IS NULL OR TRIM(routing_model) = '';

ALTER TABLE agent_profile_version
    ALTER COLUMN routing_model SET NOT NULL;

ALTER TABLE agent_profile_version
    ALTER COLUMN routing_model SET DEFAULT 'qwen-plus';
